        // Update Tours with Cloudinary URLs
        $this->updateTours($cloudinaryUrls);
        
        // Update Destinations with Cloudinary URLs
        $this->updateDestinations($cloudinaryUrls);
        
        echo "Successfully updated seeders with Cloudinary URLs!\n";
    }

    private function updateTours($urls)
    {
        $tours = Tour::all();
        
        foreach ($tours as $tour) {
            // Assign 3 random URLs to each tour
            $tourImages = [];
            for ($i = 0; $i < 3; $i++) {
                $tourImages[] = array_pop($urls) ?: $urls[array_rand($urls)];
            }
            
            $tour->images = $tourImages;
            $tour->save();
        }
    }

    private function updateDestinations($urls)
    {
        $destinations = Destination::all();
        
        foreach ($destinations as $destination) {
            // Assign 4 random URLs to each destination
            $destinationImages = [];
            for ($i = 0; $i < 4; $i++) {
                $destinationImages[] = array_pop($urls) ?: $urls[array_rand($urls)];
            }
            
            $destination->images = $destinationImages;
            $destination->save();
        }
    }
